"use strict";(self.rspackChunkhasscn_top=self.rspackChunkhasscn_top||[]).push([[50369],{89592(t,e,a){a.r(e),a.d(e,{default:()=>i});var s=a(74848),n=a(28453);function r(t){let e={a:"a",em:"em",h1:"h1",h2:"h2",img:"img",p:"p",...(0,n.R)(),...t.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsxs)(e.h1,{id:"nabu-casa-参加-matter-成员大会",children:[(0,s.jsx)(e.a,{className:"rp-header-anchor","aria-hidden":"true",href:"#nabu-casa-参加-matter-成员大会",children:"#"}),"Nabu Casa 参加 Matter 成员大会"]}),"\n",(0,s.jsx)(e.p,{children:"一句话总结：我们在日内瓦的 Matter 成员大会上代表了 Home Assistant、我们的社区以及 Open Home 愿景。我们将在 1 月举办一场 Matter 直播，向你更新我们的进展并回答你的问题。欢迎在下方评论区留下你的问题！"}),"\n",(0,s.jsx)(e.p,{children:"两周前，我和 Marcel van der Veldt、Stefan Agner 一起前往日内瓦，在 Connectivity Standards Alliance（CSA，连接标准联盟）成员大会上代表 Home Assistant、我们的社区以及 Open Home 愿景。这是一场非常重要的会议，来自世界各地的公司会在这里讨论并决定 Matter 标准及其落地实施方式。"}),"\n",(0,s.jsx)(e.p,{children:(0,s.jsx)(e.em,{children:"(Matter 是一项新的智能家居标准，承诺让每个人的智能家居设备都能跨平台、跨生态系统互相协作，同时保持本地运行和隐私保护。它由 CSA 负责开发，而 CSA 也是 Zigbee 的负责组织。)"})}),"\n",(0,s.jsxs)(e.p,{className:"img",children:["\n",(0,s.jsx)(e.img,{src:"/home-assistant/images/blog/2023-11-matter-member-meeting/matter-image.jpg"}),"\nStefan 和 Marcel\n"]}),"\n",(0,s.jsxs)(e.p,{children:["我们之所以能够参加，是因为 ",(0,s.jsx)(e.a,{href:"https://www.nabucasa.com",rel:"noopener noreferrer",target:"_blank",children:"Nabu Casa"})," 是 CSA 的成员。这项费用来自你的 Home Assistant Cloud 订阅收入（谢谢你！）。加入 CSA，能确保我们获取官方技术文档和支持，从而把 Matter 更好地构建进 Home Assistant。它也让我们在 CSA 内部拥有发声权，可以用来为 Home Assistant 用户的利益以及我们的 Open Home 愿景发声。"]}),"\n","\n",(0,s.jsx)(e.p,{children:"我们很喜欢参加这类活动，也喜欢听到遇见的人分享各种精彩故事。在与 CSA 中负责 Matter 的工程师交流时，我们发现其中很多人自己家里就运行着 Home Assistant，而且还是这个项目的热情支持者！与设备制造商交流后，我们也意识到，Home Assistant 正被当作测试平台使用，因为我们的 Matter 服务器最灵活。这是一件很棒的事，因为这会提高 Matter 设备在 Home Assistant 中良好运行的概率，毕竟这些设备已经在上面实现并测试过了。"}),"\n",(0,s.jsx)(e.p,{children:"我们参与 Matter 的开发，也意味着我们会定期与其他公司的工程师保持联系。当前市面上最受欢迎的 Matter 设备之一，Eve Energy Plug，带有自定义的能耗计量支持，而这项功能目前尚未被 Matter 标准正式支持。过去，你只能在 Eve 自家的应用中查看能耗数据。现在，我们已经与 Eve 合作，因此可以通过自定义 Matter 集群读取这些插座的测量数据，并在 Home Assistant 中展示出来！这项功能会在 Home Assistant 12 月版本中提供。如果你拥有 Eve Energy Plug，这就是我们送给你的提前圣诞礼物。"}),"\n",(0,s.jsxs)(e.h2,{id:"home-assistant-与-matter",children:[(0,s.jsx)(e.a,{className:"rp-header-anchor","aria-hidden":"true",href:"#home-assistant-与-matter",children:"#"}),"Home Assistant 与 Matter"]}),"\n",(0,s.jsx)(e.p,{children:"我们不只是加入了 CSA；我们还有专门的开发者在努力确保 Matter 成为 Home Assistant 中的一等公民。在我们看来，由于 Matter 协议具有本地运行的特性，它非常适合 Home Assistant 用户。我们的目标，是让 Home Assistant 成为一个在 CSA 注册并获得官方认证的 Matter 控制器。"}),"\n",(0,s.jsx)(e.p,{children:"为了进一步分享我们在 Matter 方面持续推进的进展，我们将在 1 月举办一场直播。直播会完整更新 Matter 的当前状态，并深入介绍我们的后续计划。具体日期我们会很快公布。"}),"\n",(0,s.jsx)(e.p,{children:"我们不希望这只是我们单方面聊 Matter 的一场直播。我们知道你对 Matter 有很多问题，也有很多地方还不够清楚，或者希望我们帮你理解。所以请在下方评论区留下你最想问的问题！"})]})}function i(){let t=arguments.length>0&&void 0!==arguments[0]?arguments[0]:{},{wrapper:e}={...(0,n.R)(),...t.components};return e?(0,s.jsx)(e,{...t,children:(0,s.jsx)(r,{...t})}):r(t)}i.__RSPRESS_PAGE_META={},i.__RSPRESS_PAGE_META["home-assistant%2Fblog%2F2023-12-04-nabu-casa-at-the-matter-member-meeting.md"]={toc:[{id:"home-assistant-与-matter",text:"Home Assistant 与 Matter",depth:2}],title:"Nabu Casa 参加 Matter 成员大会",headingTitle:"Nabu Casa 参加 Matter 成员大会",frontmatter:{title:"Nabu Casa 参加 Matter 成员大会",description:"Nabu Casa 在日内瓦的 Matter 成员大会上代表了 Home Assistant、我们的社区以及 Open Home 愿景。我们还将在 1 月举办一场关于 Matter 的专场直播！"}}}}]);